import json
with open('/tmp/inspectcode.sarif.json') as f:
    data = json.load(f)
seen = {}
for run in data.get('runs', []):
    for r in run.get('results', []):
        rule = r['ruleId']
        locs = r.get('locations', [])
        if locs:
            uri = locs[0]['physicalLocation']['artifactLocation']['uri']
            line = locs[0]['physicalLocation']['region']['startLine']
        else:
            uri = 'unknown'
            line = 0
        key = (rule, uri)
        seen[key] = seen.get(key, 0) + 1

# Group by file
by_file = {}
for (rule, uri), count in seen.items():
    if uri not in by_file:
        by_file[uri] = []
    by_file[uri].append((rule, count))

for uri in sorted(by_file.keys()):
    print(f'{uri}: {sum(c for _,c in by_file[uri])} findings')
    for rule, count in sorted(by_file[uri]):
        print(f'  {rule}: {count}')
print(f'\nTOTAL: {sum(sum(c for _,c in v) for v in by_file.values())}')
"

